SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_dep_m_constant ON sc_dep_m_constant CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_dep_m_constant() RETURNS trigger AS $BODY$
BEGIN
  --Niorn 2024-05-22 MWA Default ให้ ถ้าเป็น null  ถ้าเซตเป็น 0 มาจะต้องไม่เข้าเงื่อนไข  
  if coalesce(NEW.total_pages::text, '') = '' then NEW.total_pages := 5;end if;--จำนวนหน้าต่อเล่ม ของสมุด
  if coalesce(NEW.lines_per_page::text, '') = '' then NEW.lines_per_page := 24;end if;--จำนวนบรรทัดต่อหน้าของสมุด
  if coalesce(NEW.middle_line::text, '') = '' then NEW.middle_line := 13;end if;--บรรทัดกลาง
  if coalesce(NEW.middle_line_amount::text, '') = '' then NEW.middle_line_amount := 1;end if;--จำนวนบรรทัดกลางของสมุด
  if coalesce(NEW.day_in_year::text, '') = '' then NEW.day_in_year := 0;end if;--จำนวนวันในปี
  if coalesce(NEW.use_check_digit_status::text, '') = '' then NEW.use_check_digit_status := '0';end if;--ใช้เช็คดิจิตเป็นส่วนหนึ่งของ เลขที่บัญชี
  if coalesce(NEW.use_doc_year_status::text, '') = '' then NEW.use_doc_year_status := '0';end if;--ใช้ปีเป็นส่วนหนึงของ เลขที่บัญชี
  if coalesce(NEW.print_slip::text, '') = '' then NEW.print_slip := '1';end if;--พิมพ์สลิป
  if coalesce(NEW.print_card::text, '') = '' then NEW.print_card := '0';end if;--พิมพ์การ์ด
  if coalesce(NEW.branch_to_acc::text, '') = '' then NEW.branch_to_acc := '0';end if;  --ใช้สาขาเป็นส่วนหนึงของ เลขที่บัญชี
  if coalesce(NEW.card_lines_per_page::text, '') = '' then NEW.card_lines_per_page := 0;end if; --จำนวนบรรทัดในการ์ด
  if coalesce(NEW.card_middle_line::text, '') = '' then NEW.card_middle_line := 0;end if;--บรรทัดกลางการ์ด
  if coalesce(NEW.card_middle_line_amount::text, '') = '' then NEW.card_middle_line_amount := 0;end if; --จำนวนบรรทัดกลางในการ์ด 
  if coalesce(NEW.form_acc_no::text, '') = '' then NEW.form_acc_no := 'B';end if;--รูปแบบเลขที่บัญชี 
  /*  
  'B' = YY-BB-TT-RRRRRR-C
  'A' = BB-TT-YY-RRRRRR-C
  else = YY-TT-BB-RRRRRR-C
  */
  if coalesce(NEW.acc_no_from_branch::text, '') = '' then NEW.acc_no_from_branch := '0';end if;--ใช้สาขาเป็นส่วนหนึ่งของ เลขที่บัญชี
  if coalesce(NEW.show_fee_to_pbk::text, '') = '' then NEW.show_fee_to_pbk := '1';end if;--แสดงค่าธรรมเนียม ในสมุด
  if coalesce(NEW.dw_print_card::text, '') = '' then NEW.dw_print_card := 'rxForm.krabi.d_sc_dep_card_item_krabi';end if;--ฟอร์มการ์ด
  if coalesce(NEW.dw_print_passbook_fp::text, '') = '' then NEW.dw_print_passbook_fp := 'rxForm.port.d_sc_dep_passbook_firstpage_port';end if;--ฟอร์มปกสมุด
  if coalesce(NEW.dw_print_passbook_item::text, '') = '' then NEW.dw_print_passbook_item := 'rxForm.port.d_sc_dep_port_passbook_item';end if;--ฟอร์มสมุด
  if coalesce(NEW.dw_print_slip::text, '') = '' then NEW.dw_print_slip := 'rxForm.port.r_port_dep_form_deposit_slip';end if;--ฟอร์มสลิปเงินฝาก
  if coalesce(NEW.dw_print_interest::text, '') = '' then NEW.dw_print_interest := 'rxForm.port.r_port_dep_form_payment_int';end if;--ฟอร์มใบสำคัญจ่ายดอกเบี้ย
  if coalesce(NEW.dw_print_withdraw_fee::text, '') = '' then NEW.dw_print_withdraw_fee := 'rxForm.port.r_port_dep_form_fee_slip';end if;--ฟอร์มค่าธรรมเนียม
  if coalesce(NEW.print_book::text, '') = '' then NEW.print_book := '1';end if;--พิมพ์สมุด
  if coalesce(NEW.sortprintdwt::text, '') = '' then NEW.sortprintdwt := 'BCSIF';end if;--ลำดับการพิมพ์ Book Card Slip Interest Fee
  if coalesce(NEW.withdraw_nobook::text, '') = '' then NEW.withdraw_nobook := '0';end if;--ถอน NoBook
  if coalesce(NEW.useeditaccountnew_foropen::text, '') = '' then NEW.useeditaccountnew_foropen := '0';end if;--แก้ไขหรือระบุเลขที่บัญขีได้ ตอนเปิดบัญชี
  --Niorn 2024-05-22 MWA เงินฝากค้ำประกันให้มีผลตั้งแต่ -- R = บันทึกคำขอกู้ ( ยังไม่รองรับ ) -- A = อนุมัติสัญญาใหม่ ( ยังไม่รองรับ ) -- L = ตั้งหนี้สัญญา
  if coalesce(NEW.loan_coll_effect::text, '') = '' or NEW.loan_coll_effect !='L' then NEW.loan_coll_effect := 'L';end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_dep_m_constant() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_dep_m_constant
	BEFORE INSERT OR UPDATE ON sc_dep_m_constant FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_dep_m_constant();

